#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

bool canForm(int maxLength, const vector<int>& lengths) {
    int currentLength = 0;
    int count = 1;  // 至少有一根木棍

    for (int length : lengths) {
        // 如果当前木棍段加上该段木棍后超过最大长度，就开始新的木棍
        if (currentLength + length > maxLength) {
            count++;  // 新增一个原始木棍
            currentLength = length;  // 这段木棍放入新的木棍
        } else {
            currentLength += length;  // 否则继续将该段木棍放入当前原始木棍
        }
    }

    return count <= maxLength;  // 判断是否能拼接成一个原始木棍
}

int main() {
    int n;
    cin >> n;

    vector<int> lengths(n);
    int sumLength = 0;

    for (int i = 0; i < n; ++i) {
        cin >> lengths[i];
        sumLength += lengths[i];  // 计算所有小段木棍的总长度
    }

    int left = *max_element(lengths.begin(), lengths.end());  // 最小木棍长度是最大单段长度
    int right = sumLength;  // 最大木棍长度是所有段木棍的总和

    // 二分查找最小可能的原始木棍长度
    while (left < right) {
        int mid = left + (right - left) / 2;

        if (canForm(mid, lengths)) {
            right = mid;  // 尝试更小的木棍长度
        } else {
            left = mid + 1;  // 如果当前长度不能拼接，就增加长度
        }
    }

    cout << left << endl;  // 最小的原始木棍长度
    return 0;
}
